/* Premium serif typography for focus */
html, body, .mw-body, article {
  font-family: 'Charter', 'Georgia', serif !important;
  line-height: 1.62 !important;
  -webkit-font-smoothing: antialiased;
}

/* Clean sans-serif UI stack (Inter) */
html, body, .mw-body, article {
  font-family: 'Inter', system-ui, -apple-system, sans-serif !important;
  letter-spacing: -0.011em !important;
  line-height: 1.5 !important;
}

/* Modern coding font with ligatures */
pre, code, .blob-code, .blob-num, .react-code-text {
  font-family: 'Fira Code', 'Cascadia Code', monospace !important;
  font-variant-ligatures: contextual;
}

/* Google's signature sans-serif */
body {
  font-family: 'Roboto', sans-serif !important;
}

/* Bold geometric sans-serif */
body {
  font-family: 'Montserrat', sans-serif !important;
  text-rendering: optimizeLegibility;
}

/* Elegant high-contrast serif */
h1, h2, h3, .title {
  font-family: 'Playfair Display', serif !important;
  font-weight: 900 !important;
}

body {
  background-color: #f4ecd8 !important;
  color: #5b4636 !important;
}
.mw-body, #content {
  background: transparent !important;
  border: none !important;
}
a { color: #a05a2c !important; }

body {
  background-color: #0d1117 !important;
  color: #c9d1d9 !important;
}
.mw-body, #content {
  background: #161b22 !important;
  color: #c9d1d9 !important;
  border-color: #30363d !important;
}
a { color: #58a6ff !important; }
img { filter: brightness(0.8) contrast(1.2); }

main .prose {
  max-width: 800px !important;
  margin: 0 auto !important;
  line-height: 1.75 !important;
  font-size: 1.1rem !important;
}
.dark main .prose { color: #e5e7eb !important; }

.container-xl, .container-lg {
  max-width: none !important;
  padding-left: 32px !important;
  padding-right: 32px !important;
}
.repository-content { width: 100% !important; }

