snippets.content:
a {
    color: color-mix(in oklch, var(--color-progressive), canvasText 10%);
    font-weight: 430;
    letter-spacing: -0.025rem;
}

.vector-search-box {
  display: flex;
  justify-content: center;
}

.vector-search-box .cdx-typeahead-search--show-thumbnail.cdx-typeahead-search--auto-expand-width:not(.cdx-typeahead-search--expanded) {
    margin-left: calc((12px + 40px));
}

.cdx-search-input--has-end-button {
  border: none;
  border-radius: 16px;
}

.cdx-text-input {min-width: 300px;}

@media screen and (min-width: 1120px) {
    .mw-body {
        display: grid;
        grid-template:
            min-content min-content min-content 1fr / minmax(0, 48rem)
            min-content;
        grid-template-areas:
            "titlebar-cx ."
            "titlebar columnEnd"
            "toolbar columnEnd"
            "content columnEnd";
    }
}

vector-pinnable-header-toggle-button {
    /* display: none; */
    border: 0;
    background-color: red !important;
    color: var(--color-base, #202122);
    cursor: pointer;
    text-align: left;
    font-size: 0.75rem;
    border-radius: 16px;
}

.infobox {
    border: none;
    padding: 16px;
    border-radius: 16px;
}
.infobox .infobox-above,
.infobox .infobox-title,
.infobox caption {
    text-align: left;
}

.infobox .infobox-subheader {
    padding-bottom: 16px;
    text-align: left;
}

.mw-parser-output .sidebar {
    border: none !important;
    border-radius: 16px;
}

.mw-parser-output .sidebar-pretitle {
    padding-top: 1rem;
    line-height: 1.2em;
}

.mw-parser-output .sidebar-title-with-pretitle {
    padding-bottom: 1rem !important;
}

#tb_back_to_top {
    position: fixed;
    bottom: 16px;
    right: 16px;
    width: 32px;
    height: 32px;
    border-radius: 10px;
    border: 1px solid rgba(0, 0, 0, 0.15);
    background: rgba(255, 255, 255, 0.55);
    backdrop-filter: blur(8px);
    color: #111;
    font-size: 14px;
    cursor: pointer;
    z-index: 9999;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}
